// Parse the AI response and structure the output for email sending
const items = $input.all();

const structuredResults = items.map((item, index) => {
  let aiResponse = item.json.output || item.json.text || '';

  // Clean up the response - remove markdown code blocks if present
  aiResponse = aiResponse.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

  try {
    // Try to parse JSON response from AI
    const parsed = JSON.parse(aiResponse);

    // Get job details from the original input
    const jobTitle = item.json.job?.title || 'Position';
    const companyName = item.json.job?.companyName || 'Company';
    const jobUrl = item.json.job?.url || '';

    // Create email subject
    const emailSubject = `Application for ${jobTitle} - ${companyName}`;

    // Create email body with cover letter and resume
    const emailBody = `Dear Hiring Manager,

${parsed.cover_letter}

Thank you for considering my application.

Best regards,
Hemant Kadam

---

RESUME:

${item.json.resume?.content || 'Resume content'}

---

Job URL: ${jobUrl}
Match Score: ${parsed.match_analysis?.match_percentage}%`;

    return {
      json: {
        // Email data
        to_email: parsed.company_email,
        subject: emailSubject,
        body: emailBody,

        // Job details
        job_title: jobTitle,
        company: companyName,
        job_url: jobUrl,

        // Analysis data
        email_confidence: parsed.email_confidence,
        cover_letter: parsed.cover_letter,
        match_percentage: parsed.match_analysis?.match_percentage,
        strengths: parsed.match_analysis?.strengths,
        gaps: parsed.match_analysis?.gaps,
        application_tips: parsed.match_analysis?.application_tips
      }
    };
  } catch (e) {
    // If parsing fails, return error info
    return {
      json: {
        error: true,
        error_message: e.message,
        job_title: item.json.job?.title || 'Unknown',
        company: item.json.job?.companyName || 'Unknown',
        raw_response: aiResponse
      }
    };
  }
});

return structuredResults;

// Read structured form output — handles both form field names and pre-processed JSON keys
const f = $json;

const role      = String(f['Job Role']              || f['role']            || '').trim() || 'Software Developer';
const location  = String(f['Location']              || f['location']        || '').trim() || 'India';
const remoteRaw = String(f['Remote Work?']          || f['isRemote']        || '').toLowerCase();
const jtRaw     = String(f['Job Type']              || f['jobType']         || '').toLowerCase();
const elRaw     = String(f['Experience Level']      || f['experienceLevel'] || '').toLowerCase();
const chatId    = String(f['Your Telegram Chat ID'] || f['telegramChatId']  || '').trim();

const isRemote = remoteRaw.includes('yes') || remoteRaw === 'true';

const jtParam =
  jtRaw.includes('contract') || jtRaw.includes('freelance') ? '&f_JT=C' :
  jtRaw.includes('intern')   ? '&f_JT=I' :
  jtRaw.includes('part')     ? '&f_JT=P' : '&f_JT=F';

const remoteParam = isRemote ? '&f_WT=2' : '';

const expParam =
  elRaw.includes('entry') || elRaw.includes('fresher') ? '&f_E=1,2' :
  elRaw.includes('senior') || elRaw.includes('lead')   ? '&f_E=4,5' : '&f_E=3,4';

const searchUrl =
  'https://www.linkedin.com/jobs/search/?keywords=' + encodeURIComponent(role) +
  '&location=' + encodeURIComponent(location) +
  remoteParam + jtParam + expParam +
  '&f_TPR=r604800&position=1&pageNum=0';

return [{
  json: {
    role,
    location,
    isRemote,
    jobType:         jtRaw,
    experienceLevel: elRaw,
    searchUrl,
    telegramChatId:  chatId
  }
}];

// 1. Get all incoming items
const items = $input.all();

// 2. Score each job based on your criteria
const scoredJobs = items.map(item => {
  let score = 0;
  const data = item.json;

  if (data.companyName || data.company) score += 10;
  if (data.description && data.description.length > 100) score += 15;
  if (data.location) score += 5;
  if (data.salary) score += 8;

  if (data.applicants) {
    const applicantCount = parseInt(data.applicants);
    if (applicantCount < 10) score += 10;
    else if (applicantCount < 50) score += 5;
  }

  return {
    json: data,
    score: score
  };
});

// 3. Sort by score (highest quality first) 
// This ensures we keep the BEST job if a company has multiple listings
scoredJobs.sort((a, b) => b.score - a.score);

// 4. Filter out duplicates
const uniqueJobs = [];
const seenCompanies = new Set();

for (const item of scoredJobs) {
  // Use companyName (from your LinkedIn scrape) as the unique key
  const company = item.json.companyName || item.json.company;

  // Only add if we haven't seen this company name yet
  if (company && !seenCompanies.has(company)) {
    seenCompanies.add(company);
    uniqueJobs.push({ json: item.json });
  }
}

// 5. Return the full list of unique company jobs
return uniqueJobs;
